import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.util.Scanner;

public class XSSSecureCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize and escape user input to prevent XSS
        String sanitizedInput = "";
        try {
            sanitizedInput = ESAPI.encoder().encodeForHTML(userInput);
        } catch (EncodingException e) {
            System.err.println("Error sanitizing user input: " + e.getMessage());
            return;
        }

        String greetingMessage = "Hello, " + sanitizedInput + "!";

        // Outputting the sanitized greeting message
        System.out.println(greetingMessage);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
